          <tr><td><div class="ccell"><span class="ava" style="background:#38988A">AC</span><a class="sc-name" href="view-subbie.html">Apex Civil Group</a></div></td><td><span class="tchip">Civil Works</span><span class="tchip">Drainage</span><span class="tchip">+2</span></td><td class="trade">The Gap, QLD</td><td><span class="rr up"><span class="ms">arrow_upward</span>84%</span></td><td class="trade">2 days</td><td><span class="cap ok"><span class="ms">check</span></span></td><td><span class="cap bad"><span class="ms">close</span></span></td><td class="trade">12 May &nbsp;&middot;&nbsp; Submitted</td><td style="text-align:right"><a class="btn btn-primary btn-sm" href="new-request.html">Send request</a> <a class="btn btn-outline btn-sm" href="view-subbie.html">View</a></td></tr>
