          <tr data-state="inactive"><td><div class="ccell"><span class="ava" style="background:#2E7D32">GL</span><div><a class="sc-name" href="view-subbie.html">Greenline Landscaping</a><div><span class="tchip" style="margin-top:4px">Inactive</span></div></div></div></td><td><span class="tchip">Landscaping</span><span class="tchip">Fencing</span></td><td class="trade">Bulimba, QLD</td><td><span class="rr flat"><span class="ms">arrow_forward</span>62%</span></td><td class="trade">5 days</td><td><span class="cap bad"><span class="ms">close</span></span></td><td><span class="cap bad"><span class="ms">close</span></span></td><td class="trade">2 Feb &nbsp;&middot;&nbsp; <span class="lr-warn">Declined</span></td><td style="text-align:right"><a class="btn btn-primary btn-sm" href="new-request.html">Send request</a> <a class="btn btn-outline btn-sm" href="view-subbie.html">View</a></td></tr>
